import{_ as e,o as d,c as o,ai as r}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"Plugin System","description":"The 11-plugin architecture with shared context, event bus, epoch-based staleness, and lifecycle management.","frontmatter":{"title":"Plugin System","description":"The 11-plugin architecture with shared context, event bus, epoch-based staleness, and lifecycle management.","outline":[2,3]},"headers":[],"relativePath":"cli/plugin-system.md","filePath":"cli/plugin-system.md","lastUpdated":1772487797000}'),c={name:"cli/plugin-system.md"};function i(n,t,a,s,l,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="plugin-system" tabindex="-1">Plugin System <a class="header-anchor" href="#plugin-system" aria-label="Permalink to “Plugin System”">​</a></h1><h2 id="plugin-interface" tabindex="-1">Plugin Interface <a class="header-anchor" href="#plugin-interface" aria-label="Permalink to “Plugin Interface”">​</a></h2><p>Every screen in the TUI is implemented as a plugin conforming to <code>plugin.Plugin</code> (11 methods):</p><table tabindex="0"><thead><tr><th>Method</th><th>Signature</th><th>Purpose</th></tr></thead><tbody><tr><td><code>ID()</code></td><td><code>string</code></td><td>Unique identifier (e.g. <code>&quot;home&quot;</code>, <code>&quot;spectrum&quot;</code>)</td></tr><tr><td><code>Name()</code></td><td><code>string</code></td><td>Human-readable name for tab display</td></tr><tr><td><code>Icon()</code></td><td><code>string</code></td><td>Emoji/symbol for tab bar</td></tr><tr><td><code>Init(ctx *Context)</code></td><td><code>error</code></td><td>Initialization with shared context</td></tr><tr><td><code>Start()</code></td><td><code>tea.Cmd</code></td><td>Called when first activated</td></tr><tr><td><code>Stop()</code></td><td><code>void</code></td><td>Called on deactivation</td></tr><tr><td><code>Update(msg tea.Msg)</code></td><td><code>(Plugin, tea.Cmd)</code></td><td>Bubble Tea message handler</td></tr><tr><td><code>View(width, height int)</code></td><td><code>string</code></td><td>Render content for given dimensions</td></tr><tr><td><code>IsFocused()</code></td><td><code>bool</code></td><td>Whether this plugin is the active view</td></tr><tr><td><code>SetFocused(bool)</code></td><td><code>void</code></td><td>Sets focus state</td></tr><tr><td><code>KeyHints()</code></td><td><code>[]KeyHint</code></td><td>Footer key-hint list</td></tr></tbody></table><h2 id="plugin-context" tabindex="-1">Plugin Context <a class="header-anchor" href="#plugin-context" aria-label="Permalink to “Plugin Context”">​</a></h2><p>Shared state passed to all plugins during <code>Init()</code>:</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>PrismDir</code></td><td><code>string</code></td><td>Path to <code>.prism/</code> directory</td></tr><tr><td><code>ProjectDir</code></td><td><code>string</code></td><td>Project root directory</td></tr><tr><td><code>StoriesPath</code></td><td><code>string</code></td><td>Path to active <code>stories.json</code></td></tr><tr><td><code>Width</code></td><td><code>int</code></td><td>Terminal width</td></tr><tr><td><code>Height</code></td><td><code>int</code></td><td>Terminal height</td></tr><tr><td><code>DemoMode</code></td><td><code>bool</code></td><td>Whether running in demo mode</td></tr><tr><td><code>PrismStyle</code></td><td><code>string</code></td><td>Prism rendering style</td></tr><tr><td><code>MaxIterations</code></td><td><code>int</code></td><td>Max Spectrum iterations</td></tr><tr><td><code>Pause</code></td><td><code>int</code></td><td>Seconds between iterations</td></tr><tr><td><code>HasNerdFont</code></td><td><code>bool</code></td><td>Terminal supports Nerd Font glyphs</td></tr><tr><td><code>EventBus</code></td><td><code>*EventBus</code></td><td>Inter-plugin pub/sub communication</td></tr><tr><td><code>WorkDir</code></td><td><code>string</code></td><td>Working directory at startup</td></tr><tr><td><code>GitRoot</code></td><td><code>string</code></td><td>Git repository root directory</td></tr><tr><td><code>ConfigDir</code></td><td><code>string</code></td><td>User config directory (<code>~/.config/prism-cli</code>)</td></tr><tr><td><code>Epoch</code></td><td><code>uint64</code></td><td>Monotonic counter incremented on project switch (for staleness detection)</td></tr><tr><td><code>HasLegacyDir</code></td><td><code>bool</code></td><td>Whether a legacy <code>thoughts/</code> directory was detected</td></tr><tr><td><code>LegacyDir</code></td><td><code>string</code></td><td>Path to legacy <code>thoughts/</code> directory (for migration)</td></tr></tbody></table><h2 id="epoch-based-staleness" tabindex="-1">Epoch-Based Staleness <a class="header-anchor" href="#epoch-based-staleness" aria-label="Permalink to “Epoch-Based Staleness”">​</a></h2><p><code>Context.Epoch</code> is a critical architectural pattern. When the user switches projects (via Workspaces), <code>Registry.Reinit()</code> increments the epoch. All async <code>tea.Cmd</code> results carry the epoch at which they were dispatched. Handlers compare the message epoch against the current <code>Context.Epoch</code> — if they differ, the result is from a previous project and is silently discarded. This prevents stale file lists, story data, or Claude output from a previous project from corrupting the current view.</p><h2 id="plugin-registry" tabindex="-1">Plugin Registry <a class="header-anchor" href="#plugin-registry" aria-label="Permalink to “Plugin Registry”">​</a></h2><p>The registry manages plugin lifecycle:</p><ol><li><strong>Registration</strong> (<code>Register</code>): Validates ID uniqueness, calls <code>Init(ctx)</code> with panic recovery, first plugin is auto-activated</li><li><strong>Activation</strong> (<code>SetActive</code>): Unfocuses previous, focuses new plugin</li><li><strong>Broadcast</strong> (<code>Broadcast</code>): Routes messages to ALL plugins, collects commands</li><li><strong>Reinit</strong> (<code>Reinit</code>): Increments <code>Context.Epoch</code>, stops all plugins, re-initializes with current context (used on project switch)</li></ol><h2 id="event-bus" tabindex="-1">Event Bus <a class="header-anchor" href="#event-bus" aria-label="Permalink to “Event Bus”">​</a></h2><p>Thread-safe pub/sub communication (<code>sync.RWMutex</code>) with these event types:</p><table tabindex="0"><thead><tr><th>Event</th><th>Type String</th><th>Fields</th></tr></thead><tbody><tr><td><code>StoryCompletedEvent</code></td><td><code>&quot;story.completed&quot;</code></td><td>StoryID, StoryTitle</td></tr><tr><td><code>FileChangedEvent</code></td><td><code>&quot;file.changed&quot;</code></td><td>FilePath, Action</td></tr><tr><td><code>BranchChangedEvent</code></td><td><code>&quot;branch.changed&quot;</code></td><td>Branch</td></tr><tr><td><code>EpicSwitchedEvent</code></td><td><code>&quot;epic.switched&quot;</code></td><td>EpicName, StoriesPath</td></tr><tr><td><code>ProjectSwitchedEvent</code></td><td><code>&quot;project.switched&quot;</code></td><td>ProjectDir, PrismDir, StoriesPath</td></tr><tr><td><code>AgentStatusEvent</code></td><td><code>&quot;agent.status&quot;</code></td><td>AgentID, Status, Model, Activity</td></tr><tr><td><code>ConversationChangedEvent</code></td><td><code>&quot;conversation.changed&quot;</code></td><td>FilePath, Action</td></tr><tr><td><code>QualityGateResultEvent</code></td><td><code>&quot;gate.result&quot;</code></td><td>Gate, Passed, Output</td></tr><tr><td><code>WorktreeChangedEvent</code></td><td><code>&quot;worktree.changed&quot;</code></td><td>Action, Path</td></tr><tr><td><code>BrowserVerificationEvent</code></td><td><code>&quot;browser.verification&quot;</code></td><td>URL, Status, ScreenshotPath, ConsoleErrors</td></tr><tr><td><code>BrowserSessionEvent</code></td><td><code>&quot;browser.session&quot;</code></td><td>SessionID, Action, URL</td></tr></tbody></table><h2 id="registered-plugins-in-order" tabindex="-1">Registered Plugins (in order) <a class="header-anchor" href="#registered-plugins-in-order" aria-label="Permalink to “Registered Plugins (in order)”">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Plugin ID</th><th>Plugin Name</th><th>Source File</th><th>Lines</th></tr></thead><tbody><tr><td>1</td><td><code>home</code></td><td>Home</td><td><code>plugin_home.go</code></td><td>214</td></tr><tr><td>2</td><td><code>research</code></td><td>Research</td><td><code>plugin_research.go</code></td><td>230</td></tr><tr><td>3</td><td><code>plans</code></td><td>Plans</td><td><code>plugin_plans.go</code></td><td>245</td></tr><tr><td>4</td><td><code>spectrum</code></td><td>Spectrum</td><td><code>plugin_spectrum.go</code></td><td>1,218</td></tr><tr><td>5</td><td><code>files</code></td><td>Files</td><td><code>plugin_files.go</code></td><td>1,407</td></tr><tr><td>6</td><td><code>git</code></td><td>Git</td><td><code>plugin_git.go</code></td><td>1,530</td></tr><tr><td>7</td><td><code>agent</code></td><td>Agent</td><td><code>plugin_agent.go</code></td><td>1,051</td></tr><tr><td>8</td><td><code>monitor</code></td><td>Monitor</td><td><code>plugin_monitor.go</code></td><td>917</td></tr><tr><td>9</td><td><code>browser</code></td><td>Browser</td><td><code>plugin_browser.go</code></td><td>726</td></tr><tr><td>10</td><td><code>workspaces</code></td><td>Workspaces</td><td><code>plugin_workspaces.go</code></td><td>1,981</td></tr><tr><td>11</td><td><code>onboarding</code></td><td>Onboarding</td><td><code>plugin_onboarding.go</code></td><td>685</td></tr></tbody></table><h2 id="tab-order" tabindex="-1">Tab Order <a class="header-anchor" href="#tab-order" aria-label="Permalink to “Tab Order”">​</a></h2><p>The tab bar displays 10 tabs (excluding Splash and Onboarding):</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[1] Home  [2] Research  [3] Plans  [4] Spectrum  [5] Files  [6] Git  [7] Agent  [8] Monitor  [9] Browser  [0] Workspaces</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',20)])])}const p=e(c,[["render",i]]);export{g as __pageData,p as default};
